// ── Email notification via EmailJS ──────────────────────────────────────────
// We use the Anthropic Claude API to compose and send a notification email
// Since we can't call SMTP directly in browser, we use EmailJS public API
// NOTE: In production replace with real EmailJS service/template IDs
const sendOwnerEmail = async (booking) => {
  try {
    // Load EmailJS SDK
    if (!window.emailjs) {
      await new Promise((resolve, reject) => {
        const s = document.createElement("script");
        s.src = "https://cdn.jsdelivr.net/npm/@emailjs/browser@4/dist/email.min.js";
        s.onload = resolve;
        s.onerror = reject;
        document.head.appendChild(s);
      });
      window.emailjs.init({ publicKey: "YOUR_EMAILJS_PUBLIC_KEY" });
    }
    const serviceName = SERVICES.find(s => s.id === booking.service)?.name || booking.service;
    await window.emailjs.send("YOUR_SERVICE_ID", "YOUR_TEMPLATE_ID", {
      to_email: OWNER_EMAIL,
      to_name: "Deborah",
      booking_id: booking.id,
      client_name: booking.name,
      client_phone: booking.phone,
      client_email: booking.email,
      service: serviceName,
      date: formatDate(booking.date),
      time: booking.time,
      location_type: booking.locationType === "home" ? "Home Service" : "Visit Salon",
      address: booking.locationType === "home"
        ? [booking.address, booking.landmark, booking.area].filter(Boolean).join(", ")
        : "Client will visit salon",
    });
    console.log("Owner notification sent to", OWNER_EMAIL);
  } catch (err) {
    // Silently fail — booking still works even if email fails
    console.warn("Email notification skipped:", err.message || err);
  }
};

