// ── Time slots (custom dropdown to avoid mobile keyboard issues) ────────────
const TIME_SLOTS = ["8:00 AM","9:00 AM","10:00 AM","11:00 AM","12:00 PM","1:00 PM","2:00 PM","3:00 PM","4:00 PM","5:00 PM","6:00 PM"];

function TimeSlotPicker({ value, onChange }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", handler);
    document.addEventListener("touchstart", handler);
    return () => { document.removeEventListener("mousedown", handler); document.removeEventListener("touchstart", handler); };
  }, []);

  return (
    <div ref={ref} style={{ position: "relative" }}>
      <div
        onClick={() => setOpen(o => !o)}
        style={{ ...iStyle(false), display: "flex", justifyContent: "space-between", alignItems: "center", cursor: "pointer", userSelect: "none" }}>
        <span style={{ color: value ? G.dark : "#aaa" }}>{value || "— Choose time —"}</span>
        <span style={{ color: G.gold, fontSize: "0.8rem", transform: open ? "rotate(180deg)" : "none", transition: "0.2s" }}>▼</span>
      </div>
      {open && (
        <div style={{ position: "absolute", top: "calc(100% + 4px)", left: 0, right: 0, background: "#fff", border: "1.5px solid #e0d8cc", borderRadius: 10, zIndex: 100, maxHeight: 220, overflowY: "auto", boxShadow: "0 8px 24px rgba(0,0,0,0.12)" }}>
          {TIME_SLOTS.map(t => (
            <div key={t}
              onMouseDown={e => { e.preventDefault(); onChange(t); setOpen(false); }}
              onTouchEnd={e => { e.preventDefault(); onChange(t); setOpen(false); }}
              style={{ padding: "12px 14px", fontFamily: "'Raleway',sans-serif", fontSize: "0.88rem", color: t === value ? G.gold : G.dark, background: t === value ? "#fdf5e4" : "#fff", cursor: "pointer", borderBottom: "1px solid #f5f0e8", fontWeight: t === value ? 600 : 400 }}>
              {t}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

