// ── Stable photo uploader (outside BookingPage to keep stable identity) ──────
function StylePhotoUploader({ upd }) {
  const fileRef = useRef(null);
  const handleFile = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      upd("stylePhotoUrl", ev.target.result);
      upd("stylePhotoName", file.name);
    };
    reader.readAsDataURL(file);
  };
  return (
    <div
      onClick={() => fileRef.current && fileRef.current.click()}
      style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 10, padding: "28px 20px", borderRadius: 14, border: "2px dashed #e0d8cc", cursor: "pointer", background: "#fdfaf7", marginBottom: 16 }}>
      <div style={{ fontSize: "2rem" }}>🖼️</div>
      <div style={{ fontFamily: "'Raleway',sans-serif", fontSize: "0.82rem", color: "#7a6a5a", textAlign: "center" }}>
        Tap to upload inspiration photo<br />
        <span style={{ fontSize: "0.7rem", color: "#bbb" }}>JPG, PNG up to 10MB</span>
      </div>
      <input
        ref={fileRef}
        type="file"
        accept="image/*"
        style={{ display: "none" }}
        onChange={handleFile}
      />
    </div>
  );
}

