export default function App() {
  const [page, setPage] = useState("home");
  const [menuOpen, setMenuOpen] = useState(false);
  const [bookings, setBookings] = useState([]);
  const [currentBooking, setCurrentBooking] = useState(null);
  const [adminAuthed, setAdminAuthed] = useState(() => sessionStorage.getItem("do_admin") === "1");
  const [downloading, setDownloading] = useState(false);
  const [weeklyHighlights, setWeeklyHighlights] = useState(() => {
    try { return JSON.parse(localStorage.getItem("do_highlights") || "[]"); } catch { return []; }
  });
  const [form, setForm] = useState({
    name: "", email: "", phone: "", whatsapp: "",
    service: "", date: "", time: "", locationType: "salon",
    address: "", landmark: "", area: "",
    stylePhotoUrl: "", stylePhotoName: "",
  });
  const [formErrors, setFormErrors] = useState({});

  useEffect(() => {
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = "https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;1,300;1,400&family=Raleway:wght@300;400;500;600;700&display=swap";
    document.head.appendChild(link);
  }, []);

  useEffect(() => { window.scrollTo(0, 0); }, [page]);

  const nav = (p) => {
    setPage(p);
    setMenuOpen(false);
    // Update URL for admin page so /admin works as a direct link
    if (p === "admin") {
      window.history.pushState({}, "", "/admin");
    } else if (window.location.pathname === "/admin") {
      window.history.pushState({}, "", "/");
    }
  };
  const upd = (f, v) => setForm(prev => ({ ...prev, [f]: v }));

  const validate = () => {
    const e = {};
    if (!form.name.trim())  e.name = "Required";
    if (!form.email.trim() || !/\S+@\S+\.\S+/.test(form.email)) e.email = "Valid email required";
    if (!form.phone.trim()) e.phone = "Required";
    if (!form.service)      e.service = "Please select a service";
    if (!form.date)         e.date = "Required";
    if (!form.time)         e.time = "Required";
    if (form.locationType === "home" && !form.address.trim()) e.address = "Address required";
    setFormErrors(e);
    return Object.keys(e).length === 0;
  };

  const submitBooking = async () => {
    if (!validate()) return;
    const booking = { ...form, id: generateBookingId(), createdAt: new Date().toISOString() };
    setBookings(prev => [booking, ...prev]);
    setCurrentBooking(booking);
    nav("confirmation");
    // Fire & forget email notification
    sendOwnerEmail(booking);
  };

  // ── Download ticket as PNG image ──────────────────────────────────────────
  const downloadTicket = async () => {
    setDownloading(true);
    try {
      // Load html2canvas if not already loaded
      if (!window.html2canvas) {
        await new Promise((resolve, reject) => {
          const s = document.createElement("script");
          s.src = "https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js";
          s.onload = resolve;
          s.onerror = reject;
          document.head.appendChild(s);
        });
      }
      // Small delay to ensure fonts are rendered
      await new Promise(r => setTimeout(r, 300));
      const el = document.getElementById("ticket-el");
      if (!el) throw new Error("Ticket element not found");

      const canvas = await window.html2canvas(el, {
        backgroundColor: "#1a1a1a",
        scale: 3,
        useCORS: true,
        allowTaint: true,
        logging: false,
        imageTimeout: 0,
        onclone: (doc) => {
          // Ensure fonts load in clone
          const link = doc.createElement("link");
          link.rel = "stylesheet";
          link.href = "https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600&family=Raleway:wght@400;500;600&display=swap";
          doc.head.appendChild(link);
        }
      });

      // Convert to blob and trigger download
      canvas.toBlob((blob) => {
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `DO-Ticket-${currentBooking?.id || "appointment"}.png`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      }, "image/png", 1.0);

    } catch (err) {
      console.error("Download error:", err);
      // Fallback: open print dialog
      const el = document.getElementById("ticket-el");
      if (el) {
        const win = window.open("", "_blank", "width=500,height=700");
        win.document.write(`<!DOCTYPE html><html><head>
          <link rel="stylesheet" href="https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600&family=Raleway:wght@400;500;600&display=swap">
          <style>body{margin:0;display:flex;justify-content:center;padding:24px;background:#f5f5f5;}</style>
          </head><body>${el.outerHTML}</body></html>`);
        win.document.close();
        setTimeout(() => { win.print(); }, 800);
      }
    } finally {
      setDownloading(false);
    }
  };

  const resetBooking = () => {
    setForm({ name: "", email: "", phone: "", whatsapp: "", service: "", date: "", time: "", locationType: "salon", address: "", landmark: "", area: "", stylePhotoUrl: "", stylePhotoName: "" });
    setFormErrors({});
    setCurrentBooking(null);
    nav("booking");
  };

  // ── RENDER ─────────────────────────────────────────────────────────────────
  const renderPage = () => {
    if (page === "admin") {
      if (!adminAuthed) return <AdminLogin onSuccess={() => setAdminAuthed(true)} />;
      return <AdminDashboard bookings={bookings} onLogout={() => { sessionStorage.removeItem("do_admin"); setAdminAuthed(false); nav("home"); }} weeklyHighlights={weeklyHighlights} setWeeklyHighlights={setWeeklyHighlights} />;
    }
    switch(page) {
      case "home":         return <HomePage nav={nav} upd={upd} weeklyHighlights={weeklyHighlights} />;
      case "about":        return <AboutPage nav={nav} />;
      case "services":     return <ServicesPage nav={nav} upd={upd} />;
      case "gallery":      return <GalleryPage nav={nav} />;
      case "booking":      return <BookingPage nav={nav} upd={upd} form={form} formErrors={formErrors} submitBooking={submitBooking} />;
      case "confirmation": return <ConfirmationPage nav={nav} currentBooking={currentBooking} downloadTicket={downloadTicket} downloading={downloading} resetBooking={resetBooking} />;
      default:             return <HomePage nav={nav} upd={upd} weeklyHighlights={weeklyHighlights} />;
    }
  };

  return (
    <div style={{ fontFamily: "'Raleway',sans-serif", color: G.text, background: G.cream, minHeight: "100vh" }}>
      {/* NAV */}
      <nav style={{ position: "fixed", top: 0, left: 0, right: 0, zIndex: 1000, background: "rgba(250,247,242,0.97)", backdropFilter: "blur(12px)", borderBottom: "1px solid #e8dcc8", height: 64, display: "flex", alignItems: "center", justifyContent: "space-between", padding: "0 20px" }}>
        <button onClick={() => nav("home")} style={{ background: "none", border: "none", cursor: "pointer", padding: 0 }}>
          <Logo height={38} />
        </button>
        <div style={{ display: "flex", gap: 24, alignItems: "center" }} className="desk-nav">
          {NAV_ITEMS.map(item => (
            <button key={item.page} onClick={() => nav(item.page)}
              style={{ background: "none", border: "none", cursor: "pointer", fontFamily: "'Raleway',sans-serif", fontSize: "0.7rem", letterSpacing: "0.14em", color: page === item.page ? G.gold : G.text, textTransform: "uppercase", fontWeight: page === item.page ? 600 : 400 }}>
              {item.label}
            </button>
          ))}
          <button onClick={() => nav("booking")} style={{ ...btn("gold"), padding: "9px 22px", fontSize: "0.68rem" }}>Book Now</button>
        </div>
        <button onClick={() => setMenuOpen(m => !m)} style={{ background: "none", border: "none", cursor: "pointer", fontSize: "1.4rem", display: "none" }} className="mob-btn">
          {menuOpen ? "✕" : "☰"}
        </button>
      </nav>

      {/* Mobile menu */}
      {menuOpen && (
        <div style={{ position: "fixed", top: 64, left: 0, right: 0, bottom: 0, background: "rgba(250,247,242,0.98)", zIndex: 999, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 28 }}>
          {NAV_ITEMS.map(item => (
            <button key={item.page} onClick={() => nav(item.page)}
              style={{ background: "none", border: "none", cursor: "pointer", fontFamily: "'Cormorant Garamond',serif", fontSize: "1.8rem", color: page === item.page ? G.gold : G.dark }}>
              {item.label}
            </button>
          ))}
          <button onClick={() => nav("booking")} style={{ ...btn("gold"), fontSize: "0.9rem" }}>Book Now</button>
        </div>
      )}

      <main>{renderPage()}</main>

      {/* Floating WhatsApp */}
      <a href={`${WA_BASE}?text=Hello%2C%20I%27d%20like%20to%20book%20an%20appointment%20with%20Deborah%20Onidiri%20Hair%20Artistry.`}
        target="_blank" rel="noopener noreferrer"
        style={{ position: "fixed", bottom: 24, right: 24, zIndex: 998, background: "#25D366", borderRadius: "50%", width: 54, height: 54, display: "flex", alignItems: "center", justifyContent: "center", boxShadow: "0 4px 20px rgba(37,211,102,0.5)", textDecoration: "none" }}>
        <svg viewBox="0 0 24 24" width="28" height="28" fill="white">
          <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z" />
        </svg>
      </a>

      <style>{`
        @media (max-width: 768px) {
          .desk-nav { display: none !important; }
          .mob-btn  { display: flex !important; }
        }
        * { box-sizing: border-box; margin: 0; }
        body { margin: 0; }
        input[type=date]::-webkit-calendar-picker-indicator { filter: invert(0.4); }
        ::-webkit-scrollbar { width: 5px; height: 5px; }
        ::-webkit-scrollbar-thumb { background: #c9a84c55; border-radius: 4px; }
        button { -webkit-tap-highlight-color: transparent; }
        a { -webkit-tap-highlight-color: transparent; }
      `}</style>
    </div>
  );
}